def get_high_risk_patients():
    return [p for p in SYNTHETIC_PATIENTS if p["age"] > 60 and (p["hypertension"] == 1 or p["heart_disease"] == 1)]

def get_ml_test_batch(size=100):
    import random
    return random.sample(SYNTHETIC_PATIENTS, min(size, len(SYNTHETIC_PATIENTS)))
